parameters.jsCode:
// BER-32: Parse AI Agent JSON output into individual fields
const raw = $input.first().json.output ?? $input.first().json.text ?? '';

try {
  const parsed = JSON.parse(raw);
  return { json: parsed };
} catch (e) {
  // Fallback: return empty structure so the workflow doesn't break
  return { json: {
    Themenstichwort: '(KI-Antwort nicht parsebar)',
    Beschreibung: ['Fehler beim Parsen der KI-Antwort'],
    AnsprechpartnerBleibt: true,
    AnsprechpartnerName: '',
    AnsprechpartnerTelefon: '',
    RueckrufnummerAnders: false,
    Rueckrufnummer: ''
  }};
}
